class Solution:
    def minMoves(self, target, maxDoubles):
        moves = 0
        while target > 1 and maxDoubles > 0:
            if target % 2 == 1:
                target -= 1
            else:
                target //= 2
                maxDoubles -= 1
            moves += 1
        moves += target - 1
        return moves

