var minMoves = function(target, maxDoubles) {
    let moves = 0;
    while (target > 1 && maxDoubles > 0) {
        if (target % 2 === 1) {
            target -= 1;
        } else {
            target = Math.floor(target / 2);
            maxDoubles -= 1;
        }
        moves += 1;
    }
    moves += target - 1;
    return moves;
};
